export declare const listsStyles = "\n    ol.enumerate, ul.itemize {\n        padding-inline-start: 40px;\n        margin: 0 0 1em 0;\n    }\n    li > ol.enumerate, li > ul.itemize {\n        margin: 0;\n    }\n    ul.itemize > li {\n        position: relative;\n        min-height: 1.4em;\n        margin-bottom: 0;\n    }\n    .enumerate > .li_enumerate {\n        margin-bottom: 0;\n    }\n    .itemize > li > span.li_level, .li_enumerate.not_number > span.li_level {\n        position: absolute;\n        right: 100%;\n        white-space: nowrap;\n        width: max-content;\n        display: flex;\n        justify-content: flex-end;\n        padding-right: 10px;\n        box-sizing: border-box;\n    }\n    .li_enumerate.not_number {\n        position: relative;\n        display: inline-block;\n        list-style-type: none;\n        min-height: 1.4em;\n    }\n    .itemize > li > span.li_level .math-inline,\n    .enumerate > li > span.li_level .math-inline {\n        display: inline-block;\n    }\n";
